def assess(record: dict) -> str:
    required = {'case_id', 'metric', 'params', 'rerun_metric', 'seed', 'tolerance'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    meets = abs(record["metric"] - record["rerun_metric"]) <= record["tolerance"]
    return "PASS" if meets else 'MARK_RUN_NONREPRODUCIBLE'

valid = {"case_id": 'CASO-TAC-047-1A', **{'seed':42, 'params':{'depth': 4}, 'metric':0.81, 'rerun_metric':0.805, 'tolerance':0.01}}
invalid = {"case_id": 'CASO-TAC-047-1A', **{'seed':42, 'params':{'depth': 4}, 'metric':1000.81, 'rerun_metric':0.805, 'tolerance':0.01}}
incomplete = {k: v for k, v in valid.items() if k != 'tolerance'}
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

